# solution.py
"""Team_Collaboration_Manager.

A business collaboration platform implemented with the Python standard
library only. It provides projects, tasks, messaging with file
attachments, per-user performance dashboards, and exportable reports
(CSV or a minimal hand-written PDF).

Design highlights:
- ONE shared threading.RLock created by the facade and injected into all
  services. Every public method runs inside ``with self._lock:``.
- Deterministic, globally unique IDs from an internal counter starting
  at 1, incremented under the shared lock.
- Injectable ``now`` callable (defaults to ``datetime.now``) so tests can
  drive a deterministic clock.
- Public getters return ``copy.deepcopy`` of internal state.
- Validation ordering everywhere: NotFound -> Authorization -> Validation.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Any, Callable, Dict, List, Optional, Tuple, Union


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base error for the Team Collaboration Manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when a caller is not allowed to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Role of a user in the platform."""

    ADMIN = "admin"
    MEMBER = "member"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the platform can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Entity dataclasses
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    id: int
    filename: str
    content: bytes
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A platform user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work within a project."""

    id: int
    project_id: int
    title: str
    description: str
    assignee_id: Optional[int]
    status: TaskStatus
    deadline: Optional[datetime]
    created_at: datetime
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Message:
    """A message posted against a project or task."""

    id: int
    author_id: int
    project_id: Optional[int]
    task_id: Optional[int]
    body: str
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A performance rating with optional feedback."""

    id: int
    rater_id: int
    ratee_id: int
    task_id: Optional[int]
    score: int
    feedback: str
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------
class _IdGenerator:
    """Generates deterministic, globally unique IDs under a shared lock."""

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self._counter = 0

    def next(self) -> int:
        """Return the next unique integer ID (1, 2, 3, ...)."""
        with self._lock:
            self._counter += 1
            return self._counter


class _Store:
    """Holds all entity dicts plus secondary indexes."""

    def __init__(self) -> None:
        self.users: Dict[int, User] = {}
        self.projects: Dict[int, Project] = {}
        self.tasks: Dict[int, Task] = {}
        self.messages: Dict[int, Message] = {}
        self.ratings: Dict[int, Rating] = {}

        # Secondary indexes.
        self.username_index: Dict[str, int] = {}
        self.email_index: Dict[str, int] = {}
        self.project_tasks: Dict[int, set] = {}
        self.assignee_tasks: Dict[int, set] = {}
        self.project_messages: Dict[int, set] = {}
        self.task_messages: Dict[int, set] = {}
        self.ratee_ratings: Dict[int, set] = {}


# ---------------------------------------------------------------------------
# Services
# ---------------------------------------------------------------------------
class UserService:
    """Manages user lifecycle and lookups."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now

    def register_user(
        self,
        username: str,
        email: str,
        role: UserRole = UserRole.MEMBER,
    ) -> User:
        """Register a new user with a unique username and email."""
        with self._lock:
            if not isinstance(username, str) or not username.strip():
                raise ValidationError("username must be a non-empty string")
            if not isinstance(email, str) or not email.strip():
                raise ValidationError("email must be a non-empty string")
            if "@" not in email:
                raise ValidationError("email must contain '@'")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if username in self._store.username_index:
                raise DuplicateError("username already exists")
            if email in self._store.email_index:
                raise DuplicateError("email already exists")

            user_id = self._ids.next()
            user = User(
                id=user_id,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self._store.users[user_id] = user
            self._store.username_index[username] = user_id
            self._store.email_index[email] = user_id
            self._store.assignee_tasks.setdefault(user_id, set())
            self._store.ratee_ratings.setdefault(user_id, set())
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        """Return the user with the given id."""
        with self._lock:
            user = self._store.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")
            return copy.deepcopy(user)

    def list_users(self) -> List[User]:
        """Return all users sorted by id."""
        with self._lock:
            users = [self._store.users[k] for k in sorted(self._store.users)]
            return copy.deepcopy(users)

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        """Update mutable user fields enforcing uniqueness on change."""
        with self._lock:
            user = self._store.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")

            if username is not None:
                if not isinstance(username, str) or not username.strip():
                    raise ValidationError("username must be a non-empty string")
                if (
                    username != user.username
                    and username in self._store.username_index
                ):
                    raise DuplicateError("username already exists")
            if email is not None:
                if not isinstance(email, str) or not email.strip():
                    raise ValidationError("email must be a non-empty string")
                if "@" not in email:
                    raise ValidationError("email must contain '@'")
                if email != user.email and email in self._store.email_index:
                    raise DuplicateError("email already exists")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                del self._store.username_index[user.username]
                user.username = username
                self._store.username_index[username] = user_id
            if email is not None and email != user.email:
                del self._store.email_index[user.email]
                user.email = email
                self._store.email_index[email] = user_id
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id: int) -> None:
        """Delete a user that owns no projects and has no open tasks."""
        with self._lock:
            user = self._store.users.get(user_id)
            if user is None:
                raise NotFoundError("user not found")

            for project in self._store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns projects")

            for task_id in self._store.assignee_tasks.get(user_id, set()):
                task = self._store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has assigned non-completed tasks")

            # Clean indexes.
            del self._store.username_index[user.username]
            del self._store.email_index[user.email]
            self._store.assignee_tasks.pop(user_id, None)
            self._store.ratee_ratings.pop(user_id, None)
            del self._store.users[user_id]


class ProjectService:
    """Manages projects and cascade deletion."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now

    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        """Create a project owned by an existing user."""
        with self._lock:
            if owner_id not in self._store.users:
                raise NotFoundError("owner not found")
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("name must be a non-empty string")
            if not isinstance(start_date, datetime) or not isinstance(
                end_date, datetime
            ):
                raise ValidationError("start_date and end_date must be datetimes")
            if end_date < start_date:
                raise ValidationError("end_date must be >= start_date")

            project_id = self._ids.next()
            project = Project(
                id=project_id,
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self._store.projects[project_id] = project
            self._store.project_tasks.setdefault(project_id, set())
            self._store.project_messages.setdefault(project_id, set())
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        """Return the project with the given id."""
        with self._lock:
            project = self._store.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            return copy.deepcopy(project)

    def list_projects(self) -> List[Project]:
        """Return all projects sorted by id."""
        with self._lock:
            projects = [
                self._store.projects[k] for k in sorted(self._store.projects)
            ]
            return copy.deepcopy(projects)

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
    ) -> Project:
        """Update mutable project fields enforcing end >= start."""
        with self._lock:
            project = self._store.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            if name is not None and (
                not isinstance(name, str) or not name.strip()
            ):
                raise ValidationError("name must be a non-empty string")
            if start_date is not None and not isinstance(start_date, datetime):
                raise ValidationError("start_date must be a datetime")
            if end_date is not None and not isinstance(end_date, datetime):
                raise ValidationError("end_date must be a datetime")

            effective_start = (
                start_date if start_date is not None else project.start_date
            )
            effective_end = end_date if end_date is not None else project.end_date
            if effective_end < effective_start:
                raise ValidationError("end_date must be >= start_date")

            if name is not None:
                project.name = name
            if description is not None:
                project.description = description
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            return copy.deepcopy(project)

    def delete_project(self, project_id: int) -> None:
        """Delete a project and cascade-delete its tasks and messages."""
        with self._lock:
            project = self._store.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            # Cascade delete tasks.
            task_ids = list(self._store.project_tasks.get(project_id, set()))
            for task_id in task_ids:
                task = self._store.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    self._store.assignee_tasks.get(
                        task.assignee_id, set()
                    ).discard(task_id)
                # Cascade delete task messages.
                for msg_id in list(
                    self._store.task_messages.get(task_id, set())
                ):
                    self._store.messages.pop(msg_id, None)
                self._store.task_messages.pop(task_id, None)
            self._store.project_tasks.pop(project_id, None)

            # Cascade delete project messages.
            for msg_id in list(self._store.project_messages.get(project_id, set())):
                self._store.messages.pop(msg_id, None)
            self._store.project_messages.pop(project_id, None)

            del self._store.projects[project_id]


class TaskService:
    """Manages tasks, assignments, deadlines and status transitions."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now

    def create_task(
        self,
        project_id: int,
        title: str,
        description: str = "",
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        """Create a task in a project with optional assignee and deadline."""
        with self._lock:
            project = self._store.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")
            if assignee_id is not None and assignee_id not in self._store.users:
                raise NotFoundError("assignee not found")
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("title must be a non-empty string")
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline must be >= project.start_date"
                    )

            task_id = self._ids.next()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title,
                description=description or "",
                assignee_id=assignee_id,
                status=TaskStatus.NOT_STARTED,
                deadline=deadline,
                created_at=self._now(),
            )
            self._store.tasks[task_id] = task
            self._store.project_tasks.setdefault(project_id, set()).add(task_id)
            if assignee_id is not None:
                self._store.assignee_tasks.setdefault(assignee_id, set()).add(
                    task_id
                )
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        """Return the task with the given id."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            return copy.deepcopy(task)

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        """Return all tasks for a project sorted by id."""
        with self._lock:
            if project_id not in self._store.projects:
                raise NotFoundError("project not found")
            ids = sorted(self._store.project_tasks.get(project_id, set()))
            tasks = [self._store.tasks[t] for t in ids if t in self._store.tasks]
            return copy.deepcopy(tasks)

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        """Return all tasks assigned to a user sorted by id."""
        with self._lock:
            if assignee_id not in self._store.users:
                raise NotFoundError("user not found")
            ids = sorted(self._store.assignee_tasks.get(assignee_id, set()))
            tasks = [self._store.tasks[t] for t in ids if t in self._store.tasks]
            return copy.deepcopy(tasks)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        """Assign a task to a user, updating indexes atomically."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if assignee_id not in self._store.users:
                raise NotFoundError("assignee not found")

            if task.assignee_id is not None:
                self._store.assignee_tasks.get(task.assignee_id, set()).discard(
                    task_id
                )
            task.assignee_id = assignee_id
            self._store.assignee_tasks.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        """Move a task to a new assignee, updating indexes atomically."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if new_assignee_id not in self._store.users:
                raise NotFoundError("new assignee not found")

            if task.assignee_id is not None:
                self._store.assignee_tasks.get(task.assignee_id, set()).discard(
                    task_id
                )
            task.assignee_id = new_assignee_id
            self._store.assignee_tasks.setdefault(new_assignee_id, set()).add(
                task_id
            )
            return copy.deepcopy(task)

    def unassign_task(self, task_id: int) -> Task:
        """Clear the assignee of a task and update the index."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if task.assignee_id is not None:
                self._store.assignee_tasks.get(task.assignee_id, set()).discard(
                    task_id
                )
                task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(
        self, task_id: int, deadline: Optional[datetime]
    ) -> Task:
        """Set or clear the deadline of a task."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if deadline is not None:
                if not isinstance(deadline, datetime):
                    raise ValidationError("deadline must be a datetime")
                project = self._store.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError(
                        "deadline must be >= project.start_date"
                    )
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        """Update the status of a task and manage timestamps."""
        with self._lock:
            task = self._store.tasks.get(task_id)
            if task is None:
                raise NotFoundError("task not found")
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = self._now()
            elif status == TaskStatus.COMPLETED:
                now_value = self._now()
                if task.started_at is None:
                    task.started_at = now_value
                task.completed_at = now_value
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None

            task.status = status
            return copy.deepcopy(task)


class MessageService:
    """Manages messaging with attachments and threading."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now

    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
        parent_id: Optional[int] = None,
    ) -> Message:
        """Post a message against exactly one of a project or a task."""
        with self._lock:
            if author_id not in self._store.users:
                raise NotFoundError("author not found")
            if project_id is not None and project_id not in self._store.projects:
                raise NotFoundError("project not found")
            if task_id is not None and task_id not in self._store.tasks:
                raise NotFoundError("task not found")
            if parent_id is not None and parent_id not in self._store.messages:
                raise NotFoundError("parent message not found")

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            has_body = isinstance(body, str) and bool(body.strip())
            has_attachments = bool(attachments)
            if not has_body and not has_attachments:
                raise ValidationError(
                    "message must have a non-empty body or attachments"
                )

            built_attachments: List[Attachment] = []
            if attachments:
                for item in attachments:
                    filename, content = item
                    if not isinstance(filename, str) or not filename.strip():
                        raise ValidationError("attachment filename is required")
                    if not isinstance(content, (bytes, bytearray)):
                        raise ValidationError("attachment content must be bytes")
                    content_bytes = bytes(content)
                    built_attachments.append(
                        Attachment(
                            id=self._ids.next(),
                            filename=filename,
                            content=content_bytes,
                            size=len(content_bytes),
                            uploaded_by=author_id,
                            uploaded_at=self._now(),
                        )
                    )

            message_id = self._ids.next()
            message = Message(
                id=message_id,
                author_id=author_id,
                project_id=project_id,
                task_id=task_id,
                body=body if isinstance(body, str) else "",
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=self._now(),
            )
            self._store.messages[message_id] = message
            if project_id is not None:
                self._store.project_messages.setdefault(project_id, set()).add(
                    message_id
                )
            if task_id is not None:
                self._store.task_messages.setdefault(task_id, set()).add(
                    message_id
                )
            return copy.deepcopy(message)

    def edit_message(
        self, message_id: int, author_id: int, body: str
    ) -> Message:
        """Edit a message body; only the author may edit."""
        with self._lock:
            message = self._store.messages.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != author_id:
                raise AuthorizationError("only the author can edit")
            if not isinstance(body, str) or not body.strip():
                raise ValidationError("body must be a non-empty string")
            message.body = body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(
        self,
        message_id: int,
        author_id: int,
        filename: str,
        content: bytes,
    ) -> Message:
        """Add an attachment to a message; only the author may add."""
        with self._lock:
            message = self._store.messages.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != author_id:
                raise AuthorizationError("only the author can add attachments")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename must be a non-empty string")
            if not isinstance(content, (bytes, bytearray)):
                raise ValidationError("content must be bytes")

            content_bytes = bytes(content)
            attachment = Attachment(
                id=self._ids.next(),
                filename=filename,
                content=content_bytes,
                size=len(content_bytes),
                uploaded_by=author_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        """Return all messages for a project sorted by id."""
        with self._lock:
            if project_id not in self._store.projects:
                raise NotFoundError("project not found")
            ids = sorted(self._store.project_messages.get(project_id, set()))
            messages = [
                self._store.messages[m] for m in ids if m in self._store.messages
            ]
            return copy.deepcopy(messages)

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        """Return all messages for a task sorted by id."""
        with self._lock:
            if task_id not in self._store.tasks:
                raise NotFoundError("task not found")
            ids = sorted(self._store.task_messages.get(task_id, set()))
            messages = [
                self._store.messages[m] for m in ids if m in self._store.messages
            ]
            return copy.deepcopy(messages)

    def delete_message(self, message_id: int, author_id: int) -> None:
        """Delete a message; only the author may delete."""
        with self._lock:
            message = self._store.messages.get(message_id)
            if message is None:
                raise NotFoundError("message not found")
            if message.author_id != author_id:
                raise AuthorizationError("only the author can delete")

            if message.project_id is not None:
                self._store.project_messages.get(
                    message.project_id, set()
                ).discard(message_id)
            if message.task_id is not None:
                self._store.task_messages.get(message.task_id, set()).discard(
                    message_id
                )
            del self._store.messages[message_id]


class PerformanceService:
    """Computes per-user performance metrics and ratings."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        """Submit a rating from one user to another (1..5)."""
        with self._lock:
            if rater_id not in self._store.users:
                raise NotFoundError("rater not found")
            if ratee_id not in self._store.users:
                raise NotFoundError("ratee not found")
            if task_id is not None and task_id not in self._store.tasks:
                raise NotFoundError("task not found")
            if rater_id == ratee_id:
                raise ConflictError("cannot rate yourself")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an int")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")

            rating_id = self._ids.next()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                task_id=task_id,
                score=score,
                feedback=feedback or "",
                created_at=self._now(),
            )
            self._store.ratings[rating_id] = rating
            self._store.ratee_ratings.setdefault(ratee_id, set()).add(rating_id)
            return copy.deepcopy(rating)

    def _completed_durations(self, user_id: int) -> List[float]:
        durations: List[float] = []
        for task_id in self._store.assignee_tasks.get(user_id, set()):
            task = self._store.tasks.get(task_id)
            if (
                task is not None
                and task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        return durations

    def get_completion_rate(self, user_id: int) -> float:
        """Return completed/total over the user's assigned tasks."""
        with self._lock:
            if user_id not in self._store.users:
                raise NotFoundError("user not found")
            task_ids = self._store.assignee_tasks.get(user_id, set())
            total = 0
            completed = 0
            for task_id in task_ids:
                task = self._store.tasks.get(task_id)
                if task is None:
                    continue
                total += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
            if total == 0:
                return 0.0
            return completed / total

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        """Return mean completion seconds, or None when no completed tasks."""
        with self._lock:
            if user_id not in self._store.users:
                raise NotFoundError("user not found")
            durations = self._completed_durations(user_id)
            if not durations:
                return None
            return sum(durations) / len(durations)

    def get_ratings_summary(self, user_id: int) -> Dict[str, Any]:
        """Return a summary of the ratings received by a user."""
        with self._lock:
            if user_id not in self._store.users:
                raise NotFoundError("user not found")
            rating_ids = sorted(self._store.ratee_ratings.get(user_id, set()))
            ratings = [
                self._store.ratings[r]
                for r in rating_ids
                if r in self._store.ratings
            ]
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count > 0 else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": copy.deepcopy(ratings),
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, Any]:
        """Return an aggregate performance dashboard for a user."""
        with self._lock:
            if user_id not in self._store.users:
                raise NotFoundError("user not found")
            task_ids = self._store.assignee_tasks.get(user_id, set())
            total = 0
            completed = 0
            in_progress = 0
            not_started = 0
            durations: List[float] = []
            for task_id in task_ids:
                task = self._store.tasks.get(task_id)
                if task is None:
                    continue
                total += 1
                if task.status == TaskStatus.COMPLETED:
                    completed += 1
                    if (
                        task.started_at is not None
                        and task.completed_at is not None
                    ):
                        durations.append(
                            (task.completed_at - task.started_at).total_seconds()
                        )
                elif task.status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                elif task.status == TaskStatus.NOT_STARTED:
                    not_started += 1

            completion_rate = completed / total if total > 0 else 0.0
            avg_completion = (
                sum(durations) / len(durations) if durations else None
            )

            rating_ids = self._store.ratee_ratings.get(user_id, set())
            ratings = [
                self._store.ratings[r]
                for r in rating_ids
                if r in self._store.ratings
            ]
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count > 0
                else 0.0
            )

            return {
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_completion,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


class ReportService:
    """Builds and exports reports."""

    def __init__(
        self,
        store: _Store,
        lock: "threading.RLock",
        ids: _IdGenerator,
        now: Callable[[], datetime],
        performance: PerformanceService,
    ) -> None:
        self._store = store
        self._lock = lock
        self._ids = ids
        self._now = now
        self._performance = performance

    def project_progress_report(self, project_id: int) -> Dict[str, Any]:
        """Return progress metrics for a single project."""
        with self._lock:
            project = self._store.projects.get(project_id)
            if project is None:
                raise NotFoundError("project not found")

            now_value = self._now()
            task_ids = self._store.project_tasks.get(project_id, set())
            counts = {
                TaskStatus.NOT_STARTED.value: 0,
                TaskStatus.IN_PROGRESS.value: 0,
                TaskStatus.COMPLETED.value: 0,
            }
            total = 0
            overdue = 0
            per_assignee: Dict[Any, Dict[str, int]] = {}
            for task_id in task_ids:
                task = self._store.tasks.get(task_id)
                if task is None:
                    continue
                total += 1
                counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now_value
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                key = task.assignee_id
                bucket = per_assignee.setdefault(
                    key, {"total": 0, "completed": 0}
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1

            completion_rate = (
                counts[TaskStatus.COMPLETED.value] / total if total > 0 else 0.0
            )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "project_name": project.name,
                "total_tasks": total,
                "status_counts": counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, Any]:
        """Return per-user performance rows, optionally scoped to a project."""
        with self._lock:
            if project_id is not None and project_id not in self._store.projects:
                raise NotFoundError("project not found")

            if project_id is None:
                user_ids = list(self._store.users.keys())
            else:
                user_ids_set = set()
                for task_id in self._store.project_tasks.get(project_id, set()):
                    task = self._store.tasks.get(task_id)
                    if task is not None and task.assignee_id is not None:
                        user_ids_set.add(task.assignee_id)
                user_ids = list(user_ids_set)

            rows = []
            for user_id in sorted(user_ids):
                user = self._store.users.get(user_id)
                if user is None:
                    continue
                if project_id is None:
                    relevant_task_ids = self._store.assignee_tasks.get(
                        user_id, set()
                    )
                else:
                    relevant_task_ids = {
                        t
                        for t in self._store.assignee_tasks.get(user_id, set())
                        if t in self._store.project_tasks.get(project_id, set())
                    }

                total = 0
                completed = 0
                durations: List[float] = []
                for task_id in relevant_task_ids:
                    task = self._store.tasks.get(task_id)
                    if task is None:
                        continue
                    total += 1
                    if task.status == TaskStatus.COMPLETED:
                        completed += 1
                        if (
                            task.started_at is not None
                            and task.completed_at is not None
                        ):
                            durations.append(
                                (
                                    task.completed_at - task.started_at
                                ).total_seconds()
                            )

                completion_rate = completed / total if total > 0 else 0.0
                avg_completion = (
                    sum(durations) / len(durations) if durations else None
                )
                rating_ids = self._store.ratee_ratings.get(user_id, set())
                ratings = [
                    self._store.ratings[r]
                    for r in rating_ids
                    if r in self._store.ratings
                ]
                rating_average = (
                    sum(r.score for r in ratings) / len(ratings)
                    if ratings
                    else 0.0
                )

                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username,
                        "tasks": total,
                        "completed": completed,
                        "completion_rate": completion_rate,
                        "avg_completion_time": avg_completion,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, Any]:
        """Return an individual performance report with task summaries."""
        with self._lock:
            if user_id not in self._store.users:
                raise NotFoundError("user not found")
            dashboard = self._performance.get_user_dashboard(user_id)
            user = self._store.users[user_id]

            task_summaries = []
            for task_id in sorted(
                self._store.assignee_tasks.get(user_id, set())
            ):
                task = self._store.tasks.get(task_id)
                if task is None:
                    continue
                task_summaries.append(
                    {
                        "task_id": task.id,
                        "title": task.title,
                        "project_id": task.project_id,
                        "status": task.status.value,
                        "deadline": task.deadline,
                    }
                )

            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username,
                "tasks": task_summaries,
            }
            report.update(dashboard)
            return report

    def export_report(
        self, report: Dict[str, Any], fmt: ReportFormat
    ) -> Union[str, bytes]:
        """Export a report as CSV text or minimal PDF bytes."""
        with self._lock:
            if not isinstance(report, dict):
                raise ValidationError("report must be a dict")
            if not isinstance(fmt, ReportFormat):
                raise ValidationError("fmt must be a ReportFormat")

            if fmt == ReportFormat.CSV:
                return self._to_csv(report)
            if fmt == ReportFormat.PDF:
                return self._to_pdf(report)
            raise ValidationError("unknown report format")

    @staticmethod
    def _flatten_rows(report: Dict[str, Any]) -> List[Dict[str, Any]]:
        if isinstance(report.get("rows"), list) and report["rows"]:
            return [dict(row) for row in report["rows"]]
        if isinstance(report.get("tasks"), list) and report["tasks"]:
            return [dict(row) for row in report["tasks"]]
        # Single-row flattening of scalar fields.
        row: Dict[str, Any] = {}
        for key, value in report.items():
            if isinstance(value, (str, int, float, bool)) or value is None:
                row[key] = value
            else:
                row[key] = str(value)
        return [row]

    def _to_csv(self, report: Dict[str, Any]) -> str:
        rows = self._flatten_rows(report)
        # Build a stable, union ordering of headers.
        headers: List[str] = []
        for row in rows:
            for key in row.keys():
                if key not in headers:
                    headers.append(key)
        output = io.StringIO()
        writer = csv.DictWriter(output, fieldnames=headers)
        writer.writeheader()
        for row in rows:
            writer.writerow(
                {h: ("" if row.get(h) is None else row.get(h)) for h in headers}
            )
        return output.getvalue()

    def _to_pdf(self, report: Dict[str, Any]) -> bytes:
        lines = []
        title = str(report.get("report_type", "report"))
        lines.append("Report: " + title)
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (str, int, float, bool)) or value is None:
                lines.append("{0}: {1}".format(key, value))
        if not lines:
            lines.append("Report")
        return self._build_pdf_bytes(lines)

    @staticmethod
    def _escape_pdf_text(text: str) -> str:
        result = []
        for ch in text:
            if ch == "\\" or ch == "(" or ch == ")":
                result.append("\\" + ch)
            elif ord(ch) > 126 or ord(ch) < 32:
                result.append("?")
            else:
                result.append(ch)
        return "".join(result)

    def _build_pdf_bytes(self, lines: List[str]) -> bytes:
        # Build content stream with one text line per logical report line.
        content_lines = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
        first = True
        for line in lines:
            seg = self._escape_pdf_text(line)
            if first:
                content_lines.append("({0}) Tj".format(seg))
                first = False
            else:
                content_lines.append("T*")
                content_lines.append("({0}) Tj".format(seg))
        content_lines.append("ET")
        content = "\n".join(content_lines)
        content_bytes = content.encode("ascii", "replace")

        objects = []
        objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
        objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
        objects.append(
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
        )
        objects.append(
            b"<< /Length "
            + str(len(content_bytes)).encode("ascii")
            + b" >>\nstream\n"
            + content_bytes
            + b"\nendstream"
        )
        objects.append(
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
        )

        buffer = io.BytesIO()
        buffer.write(b"%PDF-1.4\n")
        offsets = [0]
        for index, body in enumerate(objects, start=1):
            offsets.append(buffer.tell())
            buffer.write(str(index).encode("ascii") + b" 0 obj\n")
            buffer.write(body)
            buffer.write(b"\nendobj\n")

        xref_position = buffer.tell()
        count = len(objects) + 1
        buffer.write(b"xref\n")
        buffer.write(b"0 " + str(count).encode("ascii") + b"\n")
        buffer.write(b"0000000000 65535 f \n")
        for index in range(1, count):
            buffer.write(
                ("{0:010d} 00000 n \n".format(offsets[index])).encode("ascii")
            )
        buffer.write(b"trailer\n")
        buffer.write(
            b"<< /Size " + str(count).encode("ascii") + b" /Root 1 0 R >>\n"
        )
        buffer.write(b"startxref\n")
        buffer.write(str(xref_position).encode("ascii") + b"\n")
        buffer.write(b"%%EOF\n")
        return buffer.getvalue()


